const env = typeof $env !== 'undefined' ? $env : {};
const supabaseUrl = (env.SUPABASE_URL || process.env.SUPABASE_URL || '').replace(/\/$/, '');
const serviceRoleKey = env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_ROLE_KEY || '';

if (!supabaseUrl || !serviceRoleKey) {
  throw new Error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY in n8n environment.');
}

const restHeaders = {
  apikey: serviceRoleKey,
  Authorization: `Bearer ${serviceRoleKey}`,
  'Content-Type': 'application/json',
};

async function httpRequest(options) {
  return this.helpers.httpRequest({ json: true, ...options });
}

async function supabaseGet(path) {
  return httpRequest.call(this, { method: 'GET', url: `${supabaseUrl}/rest/v1/${path}`, headers: restHeaders });
}

async function supabasePost(path, body) {
  return httpRequest.call(this, {
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/${path}`,
    headers: { ...restHeaders, Prefer: 'return=representation' },
    body,
  });
}

function enc(value) {
  return encodeURIComponent(String(value));
}

function utcDate(date = new Date()) {
  return date.toISOString().slice(0, 10);
}

function timeToMinutes(value) {
  const [hours = '0', minutes = '0'] = String(value || '00:00').split(':');
  return Number(hours) * 60 + Number(minutes);
}

function compactIds(rows, key = 'id', max = 20) {
  return (rows || []).map((row) => row[key]).filter(Boolean).slice(0, max);
}

const now = new Date();
const today = utcDate(now);
const currentMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
const currentDow = now.getUTCDay();
const runStartedAt = now.toISOString();

const schedules = await supabaseGet('check_in_schedules?select=id,coach_id,client_id,frequency,check_in_days,check_in_time&enabled=eq.true&limit=1000');
const results = [];
const stats = {
  run_started_at: runStartedAt,
  response_date: today,
  schedules_found: (schedules || []).length,
  due_count: 0,
  created_count: 0,
  skipped_not_due_count: 0,
  skipped_existing_response_count: 0,
  skipped_existing_notification_count: 0,
  error_count: 0,
};

function scheduleIsDue(schedule) {
  const days = Array.isArray(schedule.check_in_days) ? schedule.check_in_days.map(Number) : [];
  const dayMatches = schedule.frequency === 'daily' || days.includes(currentDow);
  return dayMatches && currentMinutes >= timeToMinutes(schedule.check_in_time);
}

async function existingNotification(schedule) {
  const path = `notifications?select=id&user_id=eq.${schedule.client_id}&data->>kind=eq.check_in_due&data->>schedule_id=eq.${schedule.id}&data->>response_date=eq.${today}&limit=1`;
  const rows = await supabaseGet(path);
  return rows[0];
}

for (const schedule of schedules || []) {
  try {
    if (!scheduleIsDue(schedule)) {
      stats.skipped_not_due_count += 1;
      results.push({ schedule_id: schedule.id, client_id: schedule.client_id, status: 'skipped_not_due' });
      continue;
    }
    stats.due_count += 1;

    const responses = await supabaseGet(`check_in_responses?select=id&coach_id=eq.${schedule.coach_id}&client_id=eq.${schedule.client_id}&response_date=eq.${today}&limit=1`);
    if (responses.length > 0) {
      stats.skipped_existing_response_count += 1;
      results.push({ schedule_id: schedule.id, client_id: schedule.client_id, status: 'skipped_existing_response', response_id: responses[0].id });
      continue;
    }

    const duplicate = await existingNotification(schedule);
    if (duplicate?.id) {
      stats.skipped_existing_notification_count += 1;
      results.push({ schedule_id: schedule.id, client_id: schedule.client_id, status: 'skipped_existing_notification', notification_id: duplicate.id });
      continue;
    }

    const inserted = await supabasePost('notifications', {
      user_id: schedule.client_id,
      type: 'booking_reminder',
      title: 'Check-in due',
      body: 'Your coach is waiting for today\'s check-in.',
      data: {
        kind: 'check_in_due',
        schedule_id: schedule.id,
        coach_id: schedule.coach_id,
        client_id: schedule.client_id,
        response_date: today,
        check_in_time: schedule.check_in_time,
      },
    });

    const notification = inserted[0];
    if (!notification?.id) throw new Error('Supabase did not return inserted notification id.');
    stats.created_count += 1;
    results.push({ schedule_id: schedule.id, client_id: schedule.client_id, status: 'created', notification_id: notification.id });
  } catch (error) {
    stats.error_count += 1;
    results.push({ schedule_id: schedule.id, client_id: schedule.client_id, status: 'error', error: error instanceof Error ? error.message : String(error) });
  }
}

return [
  { json: { type: 'summary', status: stats.error_count > 0 ? 'completed_with_errors' : 'completed', finished_at: new Date().toISOString(), ...stats } },
  ...results.map((result) => ({ json: { type: 'schedule_result', ...result } })),
];
